const SPREADSHEET_ID = '1Xyour-sheet-id-here'; 
const DEVICES_SHEET_NAME = 'Devices';
const HISTORY_SHEET_NAME = 'History';

// URL mẫu để fetch CSV từ Google Sheet
const getSheetUrl = (sheetName: string) => 
  `https://docs.google.com/spreadsheets/d/${SPREADSHEET_ID}/gviz/tq?tqx=out:csv&sheet=${sheetName}`;

// Helper đơn giản để parse CSV sang JSON (giả định dòng đầu là header)
const parseCSV = (csvText: string) => {
  const lines = csvText.split('\n');
  const headers = lines[0].split(',').map(h => h.replace(/"/g, '').trim());
  return lines.slice(1).map(line => {
    const values = line.split(',').map(v => v.replace(/"/g, '').trim());
    return headers.reduce((obj: any, header, i) => {
      obj[header] = values[i];
      return obj;
    }, {});
  });
};

