const DEVICES_SHEET_NAME = 'Devices';
const HISTORY_SHEET_NAME = 'Assignments';

// URL để lấy dữ liệu CSV từ Google Sheet đã Publish
const getSheetUrl = (sheetName: string) => 
  `https://docs.google.com/spreadsheets/d/${SPREADSHEET_ID}/gviz/tq?tqx=out:csv&sheet=${sheetName}`;

// Helper parse CSV sang JSON và chuẩn hóa dữ liệu
const parseCSV = (csvText: string): any[] => {
  const lines = csvText.split(/\r?\n/);
  if (lines.length < 2) return [];

  const headers = lines[0].split(',').map(h => h.replace(/"/g, '').trim().toLowerCase());

  return lines.slice(1).filter(line => line.trim() !== '').map(line => {
    // Xử lý trường hợp giá trị chứa dấu phẩy bên trong dấu ngoặc kép
    const values: string[] = [];
    let current = '';
    let inQuotes = false;
    for (let char of line) {
      if (char === '"') inQuotes = !inQuotes;
      else if (char === ',' && !inQuotes) {
        values.push(current.trim());
        current = '';
      } else {
        current += char;
      }
    }
    values.push(current.trim());

    return headers.reduce((obj: any, header, i) => {
      let val = values[i] || '';
      // Loại bỏ dấu ngoặc kép thừa nếu có
      val = val.replace(/^"|"$/g, '');
      obj[header] = val;
      return obj;
    }, {});
  });
};

