import React, { useState, useEffect, useCallback } from 'react';
import { TabType, Device, HistoryEntry, AssetStatus } from './types';
import DashboardView from './components/DashboardView';
import DevicesView from './components/DevicesView';
import Navigation from './components/Navigation';
import AddDeviceModal from './components/AddDeviceModal';

// Sử dụng URL CSV trực tiếp mà bạn đã cung cấp
const DEVICES_CSV_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vSH4eDVdibhhiEtn8gmDH2RBa1jHuzhC6LkiqhhHlCfUYOTte_1MG02NS1-m9rnxhFuHTWK0R98ejT_/pub?output=csv';

// Helper parse CSV sang JSON mạnh mẽ hơn
const parseCSV = (csvText: string): any[] => {
  const lines = csvText.split(/\r?\n/);
  if (lines.length < 2) return [];

  // Lấy header và làm sạch (lowercase, xóa khoảng trắng)
  const headers = lines[0].split(',').map(h => 
    h.replace(/"/g, '').trim().toLowerCase().replace(/\s+/g, '')
  );

  return lines.slice(1).filter(line => line.trim() !== '').map(line => {
    const values: string[] = [];
    let current = '';
    let inQuotes = false;

    // Thuật toán parse CSV chuẩn xử lý dấu ngoặc kép
    for (let i = 0; i < line.length; i++) {
      let char = line[i];
      if (char === '"') {
        if (inQuotes && line[i + 1] === '"') {
          current += '"';
          i++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === ',' && !inQuotes) {
        values.push(current.trim());
        current = '';
      } else {
        current += char;
      }
    }
    values.push(current.trim());

    return headers.reduce((obj: any, header, i) => {
      let val = values[i] || '';
      // Loại bỏ dấu ngoặc kép bao quanh giá trị
      val = val.replace(/^"|"$/g, '');
      obj[header] = val;
      return obj;
    }, {});
  });
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [devices, setDevices] = useState<Device[]>([]);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
