  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Fix: Ensure useCallback has both arguments (function and deps) and avoid syntax errors inside
  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      // Gọi trực tiếp đến link CSV đã publish
      const response = await fetch(DEVICES_CSV_URL);
      if (!response.ok) throw new Error("Không thể tải dữ liệu từ Google Sheet. Hãy đảm bảo bạn đã 'Xuất bản lên web' (Publish to web).");

      const csvText = await response.text();
      const rawData = parseCSV(csvText);

      if (rawData.length === 0) {
        throw new Error("Dữ liệu trong Google Sheet trống hoặc không đúng định dạng.");
      }

      // Ánh xạ dữ liệu từ CSV sang Interface của ứng dụng
      // Fix: Use bracket notation for keys with special characters or spaces (mã tài sản, vị trí, etc.)
      const formattedDevices: Device[] = rawData.map((d, index) => ({
        id: d.id || `row-${index}`,
