          <button onClick={fetchData} disabled={isLoading} className="text-slate-500 p-2 rounded-full hover:bg-slate-100">
            <span className={`material-symbols-outlined ${isLoading ? 'animate-spin' : ''}`}>sync</span>
          </button>
