export type AssetStatus = 'AVAILABLE' | 'ASSIGNED' | 'PENDING' | 'REPAIR';
export type UserRole = 'ADMIN' | 'STAFF';

export interface Device {
  id: string;
  tagId: string;
  name: string;
  type: string;
  location: string;
  configuration: string;
  status: AssetStatus;
  assignedTo?: string;
  lastUpdated: string;
}

export interface User {
  id: string;
  employeeId: string;
  name: string;
  role: UserRole;
  avatarUrl?: string;
}

export interface HistoryEntry {
  id: string;
  deviceId: string;
  deviceName: string;
  action: 'ASSIGN' | 'RETURN' | 'UPDATE' | 'REPAIR';
  timestamp: string;
  performer: string;
  target?: string;
  avatarUrl?: string;
}

export type TabType = 'dashboard' | 'devices' | 'users' | 'settings';

import React, { useState, useEffect, useCallback } from 'react';
import { TabType, Device, HistoryEntry, AssetStatus, User } from './types';
import DashboardView from './components/DashboardView';
import DevicesView from './components/DevicesView';
import UsersView from './components/UsersView';
import Navigation from './components/Navigation';
import AddDeviceModal from './components/AddDeviceModal';
import AddUserModal from './components/AddUserModal';

// Link lấy dữ liệu (Read-only CSV)
const DEVICES_CSV_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vSPQVVjmPXRJE3w0PhujorFo-Uj8mVwJ4Aa20i6LmsZpgmk-3pUsqajXf8Bhm68XXnROzierh4SITQ5/pub?output=csv';

const GOOGLE_SCRIPT_APP_URL = 'https://script.google.com/macros/s/AKfycbywRpgG-YElFth55EkcjLYQgH4bepTf_yMYsVI9X2ktgf9hABt6sxxa-D7Tj2ySf7Q1/exec';

const parseCSV = (csvText: string): any[] => {
  const lines = csvText.split(/\r?\n/);
  if (lines.length < 2) return [];
  const headers = lines[0].split(',').map(h => 
    h.replace(/"/g, '').trim().toLowerCase().replace(/\s+/g, '')
  );

  return lines.slice(1).filter(line => line.trim() !== '').map(line => {
    const values: string[] = [];
    let current = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      let char = line[i];
      if (char === '"') {
        if (inQuotes && line[i + 1] === '"') { current += '"'; i++; }
        else { inQuotes = !inQuotes; }
      } else if (char === ',' && !inQuotes) {
        values.push(current.trim());
        current = '';
      } else { current += char; }
    }
    values.push(current.trim());
    return headers.reduce((obj: any, header, i) => {
      let val = values[i] || '';
      val = val.replace(/^"|"$/g, '');
      obj[header] = val;
      return obj;
    }, {});
  });
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [devices, setDevices] = useState<Device[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  // Giả định User hiện tại đang đăng nhập. Mặc định là ADMIN để có thể thao tác demo.
  const [currentUser, setCurrentUser] = useState<User>({
    id: 'admin-01',
    name: 'Quản trị viên',
    employeeId: 'ADM-001',
    role: 'ADMIN'
  });

  const [isAddDeviceOpen, setIsAddDeviceOpen] = useState(false);
  const [isAddUserOpen, setIsAddUserOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await fetch(DEVICES_CSV_URL);
      if (!response.ok) throw new Error("Không thể tải dữ liệu.");
      const csvText = await response.text();
      const rawData = parseCSV(csvText);

      const formattedDevices: Device[] = rawData.map((d, index) => ({
        id: d.id || `row-${index}`,
        tagId: d.tagid || d.tag_id || d.mataisan || d['mãtài sản'] || 'N/A',
        name: d.name || d.ten || d['tên'] || 'Không tên',
        type: d.type || d.loai || d['loại'] || 'Khác',
        location: d.location || d.vitri || d['vịtrí'] || 'Chưa rõ',
        configuration: d.configuration || d.cauhinh || d['cấuhình'] || '',
        status: (d.status?.toUpperCase() as AssetStatus) || 'AVAILABLE',
        assignedTo: d.assignedto || d.nguoisudung || undefined,
        lastUpdated: d.lastupdated || new Date().toISOString()
      }));
      setDevices(formattedDevices);

      const savedUsers = localStorage.getItem('local_users');
      setUsers(savedUsers ? JSON.parse(savedUsers) : [
        { id: '1', name: 'Quản trị viên', employeeId: 'ADM-001', role: 'ADMIN' },
        { id: '2', name: 'Nhân viên kĩ thuật', employeeId: 'STF-001', role: 'STAFF' }
      ]);

    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddDevice = async (newDevice: Omit<Device, 'id' | 'status' | 'lastUpdated'>) => {
    setIsSaving(true);
    try {
      const payload = { ...newDevice, action: 'ADD_DEVICE', timestamp: new Date().toISOString() };
      await fetch(GOOGLE_SCRIPT_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      setTimeout(() => {
        setIsSaving(false);
        setIsAddDeviceOpen(false);
        fetchData();
        alert("Thiết bị đã được gửi lưu vào Google Sheet!");
      }, 1500);
    } catch (err) {
      console.error(err);
      setIsSaving(false);
    }
  };

  const handleAddUser = async (newUser: Omit<User, 'id' | 'avatarUrl'>) => {
    // Chỉ ADMIN mới có quyền thực hiện
    if (currentUser.role !== 'ADMIN') {
      alert("Bạn không có quyền thêm thành viên!");
      return;
    }

    setIsSaving(true);
    try {
      const payload = { ...newUser, action: 'ADD_USER', timestamp: new Date().toISOString() };
      await fetch(GOOGLE_SCRIPT_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      const user: User = { ...newUser, id: Math.random().toString(36).substr(2, 9) };
      const updatedUsers = [user, ...users];
      setUsers(updatedUsers);
      localStorage.setItem('local_users', JSON.stringify(updatedUsers));

      setTimeout(() => {
        setIsSaving(false);
        setIsAddUserOpen(false);
        alert(`Đã thêm thành viên ${newUser.name} thành công!`);
      }, 1000);
    } catch (err) {
      console.error(err);
      setIsSaving(false);
    }
  };

  const handleAction = (deviceId: string, action: 'ASSIGN' | 'RETURN') => {
    setDevices(prev => prev.map(d => {
      if (d.id === deviceId) {
        return {
          ...d,
          status: action === 'ASSIGN' ? 'ASSIGNED' : 'AVAILABLE',
          assignedTo: action === 'ASSIGN' ? 'User' : undefined
        };
      }
      return d;
    }));
  };

  const handleFabClick = () => {
    if (activeTab === 'users') {
      if (currentUser.role === 'ADMIN') {
        setIsAddUserOpen(true);
      } else {
        alert("Chỉ tài khoản Quản trị viên (ADMIN) mới có quyền thêm thành viên mới.");
      }
    } else {
      setIsAddDeviceOpen(true);
    }
  };

  // Hàm demo để đổi Role (dành cho mục đích kiểm thử UI)
  const toggleDemoRole = () => {
    setCurrentUser(prev => ({
      ...prev,
      role: prev.role === 'ADMIN' ? 'STAFF' : 'ADMIN'
    }));
    alert(`Đã đổi Role sang: ${currentUser.role === 'ADMIN' ? 'STAFF' : 'ADMIN'}`);
  };

  return (
    <div className="flex flex-col min-h-screen pb-20 bg-background">
      <header className="sticky top-0 z-30 flex items-center justify-between px-4 h-16 bg-white border-b border-slate-200">
        <div className="flex items-center gap-2">
          <div className="bg-primary rounded-lg p-1.5 flex items-center justify-center shadow-lg shadow-primary/20">
            <span className="material-symbols-outlined text-white text-[20px]">inventory_2</span>
          </div>
          <div className="flex flex-col">
            <span className="font-bold text-slate-800 tracking-tight leading-none">AssetFlow</span>
            <span className="text-[9px] font-bold text-primary uppercase mt-0.5 tracking-wider">{currentUser.role} MODE</span>
          </div>
        </div>
        <div className="flex items-center gap-1">
          <button 
            onClick={toggleDemoRole}
            className="text-[10px] font-bold bg-slate-100 text-slate-500 px-2 py-1 rounded-md hover:bg-slate-200 transition-colors mr-2"
          >
            Switch Role
          </button>
          <button onClick={fetchData} className="text-slate-500 p-2 rounded-full hover:bg-slate-100">
            <span className={`material-symbols-outlined ${isLoading ? 'animate-spin' : ''}`}>sync</span>
          </button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto px-4 pt-6 pb-12">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center h-64 space-y-4">
            <div className="w-10 h-10 border-4 border-primary/20 border-t-primary rounded-full animate-spin"></div>
            <p className="text-sm text-slate-400 font-medium">Synchronizing...</p>
          </div>
        ) : (
          <>
            {activeTab === 'dashboard' && <DashboardView devices={devices} history={history} onViewAll={() => setActiveTab('devices')} onAction={handleAction} />}
            {activeTab === 'devices' && <DevicesView devices={devices} onAction={handleAction} />}
            {activeTab === 'users' && <UsersView users={users} />}
            {activeTab === 'settings' && (
              <div className="flex flex-col items-center justify-center h-64">
                <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm w-full max-w-xs text-center">
                   <div className="w-16 h-16 bg-primary/10 rounded-full flex items-center justify-center mx-auto mb-4">
                      <span className="material-symbols-outlined text-primary text-3xl">person</span>
                   </div>
                   <h3 className="font-bold text-slate-800">{currentUser.name}</h3>
                   <p className="text-xs text-slate-400 mb-4">{currentUser.employeeId}</p>
                   <div className="inline-block px-3 py-1 bg-primary text-white text-[10px] font-bold rounded-full uppercase tracking-widest">
                      {currentUser.role}
                   </div>
                </div>
              </div>
            )}
          </>
        )}
      </main>

      {/* Floating Action Button - Chỉ hiện nếu không phải tab settings */}
      {activeTab !== 'settings' && activeTab !== 'dashboard' && (
        <div className="fixed bottom-24 right-6 z-40">
          <button 
            onClick={handleFabClick} 
            className={`w-14 h-14 rounded-full shadow-fab flex items-center justify-center hover:scale-110 active:scale-95 transition-all ${
              activeTab === 'users' && currentUser.role !== 'ADMIN' 
              ? 'bg-slate-300 cursor-not-allowed' 
              : 'bg-primary text-white'
            }`}
          >
            <span className="material-symbols-outlined text-[32px]">
              {activeTab === 'users' && currentUser.role !== 'ADMIN' ? 'lock' : 'add'}
            </span>
          </button>
        </div>
      )}

      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />

      {isAddDeviceOpen && <AddDeviceModal onClose={() => setIsAddDeviceOpen(false)} onSubmit={handleAddDevice} isSaving={isSaving} />}
      {isAddUserOpen && <AddUserModal onClose={() => setIsAddUserOpen(false)} onSubmit={handleAddUser} isSaving={isSaving} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { User, UserRole } from '../types';

interface AddUserModalProps {
  onClose: () => void;
  onSubmit: (user: Omit<User, 'id' | 'avatarUrl'>) => void;
  isSaving?: boolean;
}

const AddUserModal: React.FC<AddUserModalProps> = ({ onClose, onSubmit, isSaving = false }) => {
  const [formData, setFormData] = useState({
    name: '',
    employeeId: '',
    role: 'STAFF' as UserRole,
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.employeeId || isSaving) return;
    onSubmit(formData);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 bg-slate-900/50 backdrop-blur-sm animate-fadeIn">
      <div className="w-full max-w-md bg-white rounded-t-3xl sm:rounded-2xl shadow-2xl border border-slate-200 overflow-hidden transform transition-all animate-slideUp">
        <div className="px-6 pt-6 pb-4 flex items-center justify-between">
          <div>
            <h3 className="text-xl font-bold text-slate-900">Add New User</h3>
            <p className="text-sm text-slate-500">Register a new employee to the system.</p>
          </div>
          <button onClick={onClose} disabled={isSaving} className="text-slate-400 hover:text-slate-600 p-2 rounded-full">
            <span className="material-symbols-outlined">close</span>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="px-6 pb-10 sm:pb-8 space-y-4">
          <div>
            <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-1.5 ml-1">Full Name</label>
            <input 
              required
              disabled={isSaving}
              className="w-full bg-slate-50 border-slate-100 rounded-xl text-sm text-slate-800 focus:ring-primary/20 focus:border-primary py-3 px-4"
              placeholder="Nguyen Van A"
              type="text"
              value={formData.name}
              onChange={e => setFormData(prev => ({ ...prev, name: e.target.value }))}
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-1.5 ml-1">Employee ID (Mã nhân viên)</label>
            <input 
              required
              disabled={isSaving}
              className="w-full bg-slate-50 border-slate-100 rounded-xl text-sm text-slate-800 focus:ring-primary/20 focus:border-primary py-3 px-4"
              placeholder="NV-001"
              type="text"
              value={formData.employeeId}
              onChange={e => setFormData(prev => ({ ...prev, employeeId: e.target.value }))}
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-1.5 ml-1">User Role</label>
            <select 
              disabled={isSaving}
              className="form-select w-full bg-slate-50 border-slate-100 rounded-xl text-sm text-slate-800 focus:ring-primary/20 focus:border-primary py-3 px-4"
              value={formData.role}
              onChange={e => setFormData(prev => ({ ...prev, role: e.target.value as UserRole }))}
            >
              <option value="STAFF">Staff (Nhân viên)</option>
              <option value="ADMIN">Admin (Quản trị viên)</option>
            </select>
          </div>

          <div className="flex gap-3 pt-4">
            <button type="button" onClick={onClose} className="flex-1 py-3.5 rounded-xl text-sm font-bold border border-slate-200 text-slate-600">Cancel</button>
            <button type="submit" disabled={isSaving} className="flex-[2] py-3.5 rounded-xl text-sm font-bold bg-primary text-white flex items-center justify-center gap-2">
              {isSaving ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Add User'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddUserModal;

