    setIsSaving(true);
    try {
      const payload = { ...newUser, action: 'ADD_USER', timestamp: new Date().toISOString() };
      await fetch(GOOGLE_SCRIPT_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      setTimeout(() => {
        setIsSaving(false);
        setIsAddUserOpen(false);
        fetchData();
        alert(`Đã gửi yêu cầu thêm thành viên ${newUser.name} vào Sheet!`);
      }, 2000);
    } catch (err) {
      console.error(err);
      setIsSaving(false);
    }
  };

  const handleAssignUser = async (user: User) => {
    if (!assigningDevice) return;
    setIsSaving(true);
    const timestamp = new Date().toISOString();
    try {
      const payload = {
        action: 'ASSIGN_DEVICE',
        deviceId: assigningDevice.id,
        tagId: assigningDevice.tagId,
        userId: user.id,
        userName: user.name,
        deviceName: assigningDevice.name,
        timestamp: timestamp
      };
