        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      setTimeout(() => {
        setIsSaving(false);
        setAssigningDevice(null);
        fetchData();
        alert(`Đã gán ${assigningDevice.name} cho ${user.name}`);
      }, 2000);
    } catch (err) {
      console.error(err);
      setIsSaving(false);
    }
  };

  const handleAction = async (deviceId: string, action: 'ASSIGN' | 'RETURN') => {
    const device = devices.find(d => d.id === deviceId);
    if (!device) return;

    if (action === 'ASSIGN') {
      setAssigningDevice(device);
    } else {
      setIsSaving(true);
      const timestamp = new Date().toISOString();
      try {
        const payload = {
          action: 'RETURN_DEVICE',
          deviceId: deviceId,
          tagId: device.tagId,
          deviceName: device.name,
          timestamp: timestamp
        };
        await fetch(GOOGLE_SCRIPT_APP_URL, {
          method: 'POST',
          mode: 'no-cors',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        });

        setTimeout(() => {
          setIsSaving(false);
          fetchData();
          alert(`Đã thu hồi thiết bị ${device.name}`);
        }, 2000);
      } catch (err) {
        console.error(err);
        setIsSaving(false);
      }
