                   <p className="text-xs text-slate-400 mb-4">{currentUser.employeeId}</p>
                   <div className="inline-block px-3 py-1 bg-primary text-white text-[10px] font-bold rounded-full uppercase tracking-widest">
                      {currentUser.role}
                   </div>
                </div>
              </div>
            )}
          </>
        )}
      </main>

      {activeTab !== 'settings' && activeTab !== 'dashboard' && (
        <div className="fixed bottom-24 right-6 z-40">
          <button onClick={handleFabClick} className={`w-14 h-14 rounded-full shadow-fab flex items-center justify-center hover:scale-110 active:scale-95 transition-all ${activeTab === 'users' && currentUser.role !== 'ADMIN' ? 'bg-slate-300' : 'bg-primary text-white'}`}>
            <span className="material-symbols-outlined text-[32px]">{activeTab === 'users' && currentUser.role !== 'ADMIN' ? 'lock' : 'add'}</span>
          </button>
