function doPost(e) {
  var data = JSON.parse(e.postData.contents);
  var ss = SpreadsheetApp.getActiveSpreadsheet();

  if (data.action === 'ADD_DEVICE') {
    var sheet = ss.getSheets()[0];
    // Thứ tự cột giả định: ID, TagID, Name, Type, Location, Config, Status, AssignedTo, LastUpdated
    sheet.appendRow(["ID-" + Date.now(), data.tagId, data.name, data.type, data.location, data.configuration, "AVAILABLE", "", data.timestamp]);
  } 
  else if (data.action === 'ADD_USER') {
    var sheet = ss.getSheetByName("Users") || ss.insertSheet("Users");
    sheet.appendRow(["U-" + Date.now(), data.name, data.employeeId, data.role, data.timestamp]);
  }
  else if (data.action === 'EDIT_DEVICE') {
    var devSheet = ss.getSheets()[0];
    var devData = devSheet.getDataRange().getValues();
    var tagIdToFind = data.tagId || data.tagid || data.mataisan;

    for (var i = 1; i < devData.length; i++) {
      if (devData[i][1] == tagIdToFind) { // So khớp Tag ID ở cột B (index 1)
        devSheet.getRange(i + 1, 3).setValue(data.name);          // Cột C: Tên
        devSheet.getRange(i + 1, 4).setValue(data.type);          // Cột D: Loại
        devSheet.getRange(i + 1, 5).setValue(data.location);      // Cột E: Vị trí
        devSheet.getRange(i + 1, 6).setValue(data.configuration); // Cột F: Cấu hình
        devSheet.getRange(i + 1, 7).setValue(data.status);        // Cột G: Trạng thái
        devSheet.getRange(i + 1, 9).setValue(data.timestamp);     // Cột I: Cập nhật cuối
        break;
      }
    }
  }
  else if (data.action === 'ASSIGN_DEVICE' || data.action === 'RETURN_DEVICE') {
    var devSheet = ss.getSheets()[0];
    var devData = devSheet.getDataRange().getValues();
    var tagIdToFind = data.tagId || data.tagid || data.mataisan;

    for (var i = 1; i < devData.length; i++) {
      if (devData[i][1] == tagIdToFind) { 
        var newStatus = (data.action === 'ASSIGN_DEVICE') ? 'ASSIGNED' : 'AVAILABLE';
        var assignedTo = (data.action === 'ASSIGN_DEVICE') ? data.userName : "";
        devSheet.getRange(i + 1, 7).setValue(newStatus);
        devSheet.getRange(i + 1, 8).setValue(assignedTo);
        devSheet.getRange(i + 1, 9).setValue(data.timestamp);
        break;
      }
    }

    var histSheet = ss.getSheetByName("History") || ss.insertSheet("History");
    if (histSheet.getLastRow() === 0) {
      histSheet.appendRow(["Timestamp", "Tag ID", "Action", "Performed By", "Target User"]);
    }
    histSheet.appendRow([
      data.timestamp, 
      tagIdToFind, 
      data.action, 
      data.performedBy || "Admin", 
      data.userName || "Storage"
    ]);
  }

  return ContentService.createTextOutput(JSON.stringify({ "result": "success" }))
    .setMimeType(ContentService.MimeType.JSON);
}
