Chào bạn! Tôi đã hiểu yêu cầu của bạn. Tôi sẽ thực hiện hai việc:
1.  **Cung cấp mã Google Apps Script mới**: Đã sửa lỗi để xử lý được hành động `EDIT_DEVICE`.
2.  **Chuyển toàn bộ mã nguồn Frontend sang JavaScript**: Loại bỏ các định nghĩa kiểu (types/interfaces) phức tạp của TypeScript để mã nguồn gọn gàng và dễ hiểu hơn đối với bạn.

### Bước 1: Cập nhật Google Apps Script
Bạn hãy copy toàn bộ mã này và thay thế mã cũ trong Google Apps Script (phần `doPost`):

```javascript
function doPost(e) {
  var data = JSON.parse(e.postData.contents);
  var ss = SpreadsheetApp.getActiveSpreadsheet();

  // Xác định hành động
  if (data.action === 'ADD_DEVICE') {
    var sheet = ss.getSheets()[0];
    // Thứ tự: ID, TagID, Name, Type, Location, Config, Status, AssignedTo, LastUpdated
    sheet.appendRow(["ID-" + Date.now(), data.tagId, data.name, data.type, data.location, data.configuration, "AVAILABLE", "", data.timestamp]);
  } 
  else if (data.action === 'ADD_USER') {
    var sheet = ss.getSheetByName("Users") || ss.insertSheet("Users");
    sheet.appendRow(["U-" + Date.now(), data.name, data.employeeId, data.role, data.timestamp]);
  }
  else if (data.action === 'EDIT_DEVICE') {
    var devSheet = ss.getSheets()[0];
    var devData = devSheet.getDataRange().getValues();
    var tagIdToFind = data.tagId || data.tagid;

    // Tìm hàng có Tag ID khớp để cập nhật
    for (var i = 1; i < devData.length; i++) {
      if (devData[i][1] == tagIdToFind) { 
        // Giả sử: Cột 3 là Name, 4 là Type, 5 là Location, 6 là Config, 7 là Status, 9 là LastUpdated
        devSheet.getRange(i + 1, 3).setValue(data.name);          // Tên
        devSheet.getRange(i + 1, 4).setValue(data.type);          // Loại
        devSheet.getRange(i + 1, 5).setValue(data.location);      // Vị trí
        devSheet.getRange(i + 1, 6).setValue(data.configuration); // Cấu hình
        devSheet.getRange(i + 1, 7).setValue(data.status);        // Trạng thái
        devSheet.getRange(i + 1, 9).setValue(data.timestamp);     // Cập nhật cuối
        break;
      }
    }
  }
  else if (data.action === 'ASSIGN_DEVICE' || data.action === 'RETURN_DEVICE') {
    var devSheet = ss.getSheets()[0];
    var devData = devSheet.getDataRange().getValues();
    var tagIdToFind = data.tagId || data.tagid;

    for (var i = 1; i < devData.length; i++) {
      if (devData[i][1] == tagIdToFind) { 
        var newStatus = (data.action === 'ASSIGN_DEVICE') ? 'ASSIGNED' : 'AVAILABLE';
        var assignedTo = (data.action === 'ASSIGN_DEVICE') ? data.userName : "";
        devSheet.getRange(i + 1, 7).setValue(newStatus);
        devSheet.getRange(i + 1, 8).setValue(assignedTo);
        devSheet.getRange(i + 1, 9).setValue(data.timestamp);
        break;
      }
    }

    var histSheet = ss.getSheetByName("History") || ss.insertSheet("History");
    if (histSheet.getLastRow() === 0) {
      histSheet.appendRow(["Timestamp", "Tag ID", "Action", "Performed By", "Target User"]);
    }
    histSheet.appendRow([data.timestamp, tagIdToFind, data.action, data.performedBy || "Admin", data.userName || "Kho"]);
  }

  return ContentService.createTextOutput(JSON.stringify({ "result": "success" }))
    .setMimeType(ContentService.MimeType.JSON);
}
