      await fetch(GOOGLE_SCRIPT_APP_URL, { method: 'POST', mode: 'no-cors', headers: { 'Content-Type': 'text/plain' }, body: JSON.stringify(payload) });
      setTimeout(() => { setIsSaving(false); setIsAddDeviceOpen(false); fetchData(); }, 2000);
    } catch (err) { setIsSaving(false); }
  };

  const handleAction = async (deviceId, action) => {
    const device = devices.find(d => d.id === deviceId);
    if (!device) return;
    if (action === 'ASSIGN') setAssigningDevice(device);
    else {
      setIsSaving(true);
      try {
        const payload = { action: 'RETURN_DEVICE', tagId: device.tagId, timestamp: new Date().toLocaleString('vi-VN'), performedBy: currentUser.name };
        await fetch(GOOGLE_SCRIPT_APP_URL, { method: 'POST', mode: 'no-cors', headers: { 'Content-Type': 'text/plain' }, body: JSON.stringify(payload) });
        setTimeout(() => { setIsSaving(false); fetchData(); }, 2000);
      } catch (err) { setIsSaving(false); }
    }
  };

  const handleAssignSubmit = async (user) => {
    if (!assigningDevice) return;
    setIsSaving(true);
    try {
      const payload = { action: 'ASSIGN_DEVICE', tagId: assigningDevice.tagId, userName: user.name, timestamp: new Date().toLocaleString('vi-VN'), performedBy: currentUser.name };
