          <div className="bg-primary rounded-lg p-1.5 flex items-center justify-center">
            <span className="material-symbols-outlined text-white text-[20px]">inventory_2</span>
          </div>
          <span className="font-bold text-slate-800 tracking-tight">AssetFlow</span>
        </div>
        <button onClick={fetchData} className="text-slate-500 p-2 rounded-full hover:bg-slate-100">
          <span className={`material-symbols-outlined ${isLoading ? 'animate-spin' : ''}`}>sync</span>
        </button>
      </header>

      <main className="flex-1 overflow-y-auto px-4 pt-6">
        {isLoading ? <div className="text-center py-10">Đang tải...</div> : (
          <>
            {activeTab === 'dashboard' && <DashboardView devices={devices} history={history} onViewAll={() => setActiveTab('devices')} onAction={handleAction} onEdit={setEditingDevice} />}
            {activeTab === 'devices' && <DevicesView devices={devices} onAction={handleAction} onEdit={setEditingDevice} />}
            {activeTab === 'users' && <UsersView users={users} />}
          </>
        )}
      </main>

      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
      {isAddDeviceOpen && <AddDeviceModal onClose={() => setIsAddDeviceOpen(false)} onSubmit={handleAddDevice} isSaving={isSaving} />}
      {assigningDevice && <AssignUserModal users={users} onClose={() => setAssigningDevice(null)} onSubmit={handleAssignSubmit} isSaving={isSaving} />}
      {editingDevice && <EditDeviceModal device={editingDevice} onClose={() => setEditingDevice(null)} onSubmit={handleEditDevice} isSaving={isSaving} />}

      {activeTab !== 'settings' && (
