/**
 * Google Apps Script Backend cho AssetFlow
 * Chức năng: Phục vụ giao diện Web App và xử lý dữ liệu POST
 */

function doGet(e) {
  return HtmlService.createHtmlOutputFromFile('index')
    .setTitle('AssetFlow - Hệ thống Quản lý Tài sản')
    .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL)
    .addMetaTag('viewport', 'width=device-width, initial-scale=1');
}

function doPost(e) {
  var result = { "status": "error", "message": "Unknown action" };
  try {
    var data = JSON.parse(e.postData.contents);
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var timestamp = data.timestamp || new Date().toLocaleString('vi-VN');

    // 1. XỬ LÝ THÊM THIẾT BỊ MỚI
    if (data.action === 'ADD_DEVICE') {
      var sheet = ss.getSheets()[0];
      // Cấu trúc: ID, TagID, Tên, Loại, Vị trí, Cấu hình, Trạng thái, Người dùng, Cập nhật cuối
      sheet.appendRow(["ID-" + Date.now(), data.tagId, data.name, data.type, data.location, data.configuration, "AVAILABLE", "", timestamp]);
      result = { "status": "success", "message": "Đã thêm thiết bị" };
    } 

    // 2. XỬ LÝ CHỈNH SỬA THIẾT BỊ
    else if (data.action === 'EDIT_DEVICE') {
      var devSheet = ss.getSheets()[0];
      var devData = devSheet.getDataRange().getValues();
      var tagIdToFind = data.tagId || data.tagid;

      for (var i = 1; i < devData.length; i++) {
        if (devData[i][1] == tagIdToFind) { // So khớp Tag ID ở cột B
          devSheet.getRange(i + 1, 3).setValue(data.name);          // Cột C: Tên
          devSheet.getRange(i + 1, 4).setValue(data.type);          // Cột D: Loại
          devSheet.getRange(i + 1, 5).setValue(data.location);      // Cột E: Vị trí
          devSheet.getRange(i + 1, 6).setValue(data.configuration); // Cột F: Cấu hình
          devSheet.getRange(i + 1, 7).setValue(data.status);        // Cột G: Trạng thái
          devSheet.getRange(i + 1, 9).setValue(timestamp);          // Cột I: Cập nhật cuối
          break;
        }
      }
      result = { "status": "success", "message": "Đã cập nhật thiết bị" };
    }

    // 3. XỬ LÝ THÊM NGƯỜI DÙNG
    else if (data.action === 'ADD_USER') {
      var sheet = ss.getSheetByName("Users") || ss.insertSheet("Users");
      sheet.appendRow(["U-" + Date.now(), data.name, data.employeeId, data.role, timestamp]);
      result = { "status": "success", "message": "Đã thêm người dùng" };
    }

    // 4. XỬ LÝ CẤP PHÁT / THU HỒI
    else if (data.action === 'ASSIGN_DEVICE' || data.action === 'RETURN_DEVICE') {
      var devSheet = ss.getSheets()[0];
      var devData = devSheet.getDataRange().getValues();
      var tagIdToFind = data.tagId || data.tagid;

      for (var i = 1; i < devData.length; i++) {
        if (devData[i][1] == tagIdToFind) { 
          var newStatus = (data.action === 'ASSIGN_DEVICE') ? 'ASSIGNED' : 'AVAILABLE';
          var assignedTo = (data.action === 'ASSIGN_DEVICE') ? data.userName : "";
          devSheet.getRange(i + 1, 7).setValue(newStatus);
          devSheet.getRange(i + 1, 8).setValue(assignedTo);
          devSheet.getRange(i + 1, 9).setValue(timestamp);
          break;
        }
      }

      // Ghi lịch sử
      var histSheet = ss.getSheetByName("History") || ss.insertSheet("History");
      if (histSheet.getLastRow() === 0) {
        histSheet.appendRow(["Timestamp", "Tag ID", "Action", "Performed By", "Target User"]);
      }
      histSheet.appendRow([timestamp, tagIdToFind, data.action, data.performedBy || "Admin", data.userName || "Kho"]);
      result = { "status": "success", "message": "Đã cập nhật trạng thái và lịch sử" };
    }
  } catch (e) {
    result = { "status": "error", "message": e.toString() };
  }

  return ContentService.createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

import React, { useState, useEffect, useCallback } from 'react';
import DashboardView from './components/DashboardView';
