import React, { useState, useEffect, useCallback } from 'react';
import { TabType, Device, User, HistoryEntry } from './types';
import DashboardView from './components/DashboardView';
import DevicesView from './components/DevicesView';
import UsersView from './components/UsersView';
import Navigation from './components/Navigation';
import AddDeviceModal from './components/AddDeviceModal';
import AddUserModal from './components/AddUserModal';
import AssignUserModal from './components/AssignUserModal';
import EditDeviceModal from './components/EditDeviceModal';

// CẤU HÌNH CÁC ĐƯỜNG DẪN DỮ LIỆU
const DEVICES_CSV_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vSPQVVjmPXRJE3w0PhujorFo-Uj8mVwJ4Aa20i6LmsZpgmk-3pUsqajXf8Bhm68XXnROzierh4SITQ5/pub?gid=0&single=true&output=csv';
const USERS_CSV_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vSPQVVjmPXRJE3w0PhujorFo-Uj8mVwJ4Aa20i6LmsZpgmk-3pUsqajXf8Bhm68XXnROzierh4SITQ5/pub?gid=1789914936&single=true&output=csv';
const HISTORY_CSV_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vSPQVVjmPXRJE3w0PhujorFo-Uj8mVwJ4Aa20i6LmsZpgmk-3pUsqajXf8Bhm68XXnROzierh4SITQ5/pub?gid=801829903&single=true&output=csv';

// THAY URL NÀY BẰNG URL WEB APP SAU KHI DEPLOY GOOGLE APPS SCRIPT
const GOOGLE_SCRIPT_APP_URL = 'https://script.google.com/macros/s/AKfycbywRpgG-YElFth55EkcjLYQgH4bepTf_yMYsVI9X2ktgf9hABt6sxxa-D7Tj2ySf7Q1/exec';

const parseCSV = (csvText: string) => {
  const lines = csvText.split(/\r?\n/);
  if (lines.length < 2) return [];
  const headers = lines[0].split(',').map(h => h.replace(/"/g, '').trim().toLowerCase().replace(/\s+/g, ''));
  return lines.slice(1).filter(line => line.trim() !== '').map(line => {
    const values = [];
    let current = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      let char = line[i];
      if (char === '"') {
        if (inQuotes && line[i + 1] === '"') { current += '"'; i++; }
        else { inQuotes = !inQuotes; }
      } else if (char === ',' && !inQuotes) {
        values.push(current.trim());
        current = '';
      } else { current += char; }
    }
    values.push(current.trim());
    return headers.reduce((obj: any, header, i) => {
      let val = values[i] || '';
      val = val.replace(/^"|"$/g, '');
      obj[header] = val;
      return obj;
    }, {});
  });
};

const App = () => {
  // Fix: Explicitly type activeTab state as TabType to resolve assignment error on line 232
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [devices, setDevices] = useState<Device[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [currentUser] = useState<User>({ id: 'admin-01', name: 'Quản trị viên', employeeId: 'ADM-001', role: 'ADMIN' });

  const [isAddDeviceOpen, setIsAddDeviceOpen] = useState(false);
  const [isAddUserOpen, setIsAddUserOpen] = useState(false);
  const [assigningDevice, setAssigningDevice] = useState<Device | null>(null);
  const [editingDevice, setEditingDevice] = useState<Device | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const cb = `cb=${Date.now()}`;
      const [devicesRes, usersRes, historyRes] = await Promise.all([
        fetch(`${DEVICES_CSV_URL}&${cb}`),
        fetch(`${USERS_CSV_URL}&${cb}`),
        fetch(`${HISTORY_CSV_URL}&${cb}`)
      ]);
      const devicesCsv = await devicesRes.text();
      const usersCsv = await usersRes.text();
      const historyCsv = await (historyRes.ok ? historyRes.text() : Promise.resolve(''));

      const rawDevices = parseCSV(devicesCsv);
      const rawUsers = parseCSV(usersCsv);
      const rawHistory = parseCSV(historyCsv);

      const formattedDevices: Device[] = rawDevices.map((d: any, index) => ({
        id: d.id || `dev-${index}`,
        tagId: d.tagid || d.tag_id || d.mataisan || 'N/A',
        name: d.name || d.ten || 'Không tên',
        type: d.type || d.loai || 'Khác',
        location: d.location || d.vitri || 'Chưa rõ',
        configuration: d.configuration || d.cauhinh || '',
        status: (d.status?.toUpperCase()) || 'AVAILABLE',
        assignedTo: d.assignedto || d.nguoisudung || undefined,
        lastUpdated: d.lastupdated || new Date().toLocaleString('vi-VN')
      }));
      setDevices(formattedDevices);

      const formattedUsers: User[] = rawUsers.map((u: any, index) => ({
        id: u.id || `user-${index}`,
        name: u.name || u.ten || 'Unknown User',
        employeeId: u.employeeid || u.manhanvien || 'N/A',
        role: u.role?.toUpperCase() === 'ADMIN' ? 'ADMIN' : 'STAFF',
        avatarUrl: u.avatarurl || undefined
      }));
      setUsers(formattedUsers);

      const formattedHistory: HistoryEntry[] = rawHistory.map((h: any, index) => {
        const device = formattedDevices.find(d => d.tagId === h.tagid);
        return {
          id: h.id || `hist-${index}`,
          deviceId: h.tagid || 'N/A',
          deviceName: device ? device.name : (h.devicename || 'Thiết bị #' + h.tagid),
          action: h.action?.toUpperCase().includes('ASSIGN') ? 'ASSIGN' : h.action?.toUpperCase().includes('RETURN') ? 'RETURN' : 'UPDATE',
          timestamp: h.timestamp || 'Gần đây',
          performer: h.performedby || h.performer || 'Hệ thống',
          target: h.targetuser || h.target || 'Kho'
        };
      });
      setHistory(formattedHistory.reverse());
    } catch (err) {
      console.error(err);
      setError("Không thể đồng bộ dữ liệu. Kiểm tra link CSV.");
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  // HÀM XỬ LÝ CHỈNH SỬA THIẾT BỊ
  const handleEditDevice = async (updatedDevice: Device) => {
    setIsSaving(true);
    // Cập nhật UI ngay lập tức (Optimistic Update)
    const originalDevices = [...devices];
    setDevices(prev => prev.map(d => d.id === updatedDevice.id ? updatedDevice : d));

    try {
      const payload = { 
        ...updatedDevice, 
        action: 'EDIT_DEVICE', 
        tagid: updatedDevice.tagId, 
        timestamp: new Date().toLocaleString('vi-VN'),
        performedBy: currentUser.name 
      };

      await fetch(GOOGLE_SCRIPT_APP_URL, { 
        method: 'POST', 
        mode: 'no-cors', 
        headers: { 'Content-Type': 'text/plain' }, 
        body: JSON.stringify(payload) 
      });

      setTimeout(() => {
        setIsSaving(false);
        setEditingDevice(null);
        alert("Đã lưu thay đổi vào Google Sheet!");
        fetchData(); // Đồng bộ lại dữ liệu
      }, 2000);
    } catch (err) {
      setDevices(originalDevices);
      setIsSaving(false);
      alert("Lỗi kết nối Server.");
    }
  };

  const handleAddDevice = async (newDevice: Omit<Device, 'id' | 'status' | 'lastUpdated'>) => {
    setIsSaving(true);
    try {
      const payload = { ...newDevice, action: 'ADD_DEVICE', timestamp: new Date().toLocaleString('vi-VN') };
      await fetch(GOOGLE_SCRIPT_APP_URL, { method: 'POST', mode: 'no-cors', headers: { 'Content-Type': 'text/plain' }, body: JSON.stringify(payload) });
      setTimeout(() => { setIsSaving(false); setIsAddDeviceOpen(false); fetchData(); }, 2000);
    } catch (err) { setIsSaving(false); }
  };

  const handleAction = async (deviceId: string, action: 'ASSIGN' | 'RETURN') => {
    const device = devices.find(d => d.id === deviceId);
    if (!device) return;
    if (action === 'ASSIGN') setAssigningDevice(device);
    else {
      setIsSaving(true);
      try {
        const payload = { action: 'RETURN_DEVICE', tagId: device.tagId, timestamp: new Date().toLocaleString('vi-VN'), performedBy: currentUser.name };
        await fetch(GOOGLE_SCRIPT_APP_URL, { method: 'POST', mode: 'no-cors', headers: { 'Content-Type': 'text/plain' }, body: JSON.stringify(payload) });
        setTimeout(() => { setIsSaving(false); fetchData(); }, 2000);
      } catch (err) { setIsSaving(false); }
    }
  };

  const handleAssignSubmit = async (user: User) => {
    if (!assigningDevice) return;
    setIsSaving(true);
    try {
      const payload = { 
        action: 'ASSIGN_DEVICE', 
        tagId: assigningDevice.tagId, 
        userName: user.name, 
        timestamp: new Date().toLocaleString('vi-VN'), 
        performedBy: currentUser.name 
      };
      await fetch(GOOGLE_SCRIPT_APP_URL, { method: 'POST', mode: 'no-cors', headers: { 'Content-Type': 'text/plain' }, body: JSON.stringify(payload) });
      setTimeout(() => { setIsSaving(false); setAssigningDevice(null); fetchData(); }, 2000);
    } catch (err) { setIsSaving(false); }
  };

  return (
    <div className="flex flex-col min-h-screen pb-20 bg-background">
      <header className="sticky top-0 z-30 flex items-center justify-between px-4 h-16 bg-white border-b border-slate-200">
        <div className="flex items-center gap-2">
          <div className="bg-primary rounded-lg p-1.5 flex items-center justify-center shadow-lg shadow-primary/20">
            <span className="material-symbols-outlined text-white text-[20px]">inventory_2</span>
          </div>
          <span className="font-bold text-slate-800 tracking-tight">AssetFlow</span>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={fetchData} className="text-slate-500 p-2 rounded-full hover:bg-slate-100">
            <span className={`material-symbols-outlined ${isLoading ? 'animate-spin' : ''}`}>sync</span>
          </button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto px-4 pt-6">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center h-64">
            <div className="w-8 h-8 border-4 border-primary/20 border-t-primary rounded-full animate-spin mb-4"></div>
            <p className="text-xs text-slate-400 font-medium">Đang tải dữ liệu...</p>
          </div>
        ) : (
          <>
            {activeTab === 'dashboard' && <DashboardView devices={devices} history={history} onViewAll={() => setActiveTab('devices')} onAction={handleAction} onEdit={setEditingDevice} />}
            {activeTab === 'devices' && <DevicesView devices={devices} onAction={handleAction} onEdit={setEditingDevice} />}
            {activeTab === 'users' && <UsersView users={users} />}
          </>
        )}
      </main>

      {/* Line 232 Fix: Explicit TabType ensures compatibility with Navigation component props */}
      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
      {isAddDeviceOpen && <AddDeviceModal onClose={() => setIsAddDeviceOpen(false)} onSubmit={handleAddDevice} isSaving={isSaving} />}
      {assigningDevice && <AssignUserModal users={users} onClose={() => setAssigningDevice(null)} onSubmit={handleAssignSubmit} isSaving={isSaving} />}
      {editingDevice && <EditDeviceModal device={editingDevice} onClose={() => setEditingDevice(null)} onSubmit={handleEditDevice} isSaving={isSaving} />}

      {activeTab !== 'settings' && activeTab !== 'dashboard' && (
        <button onClick={() => setIsAddDeviceOpen(true)} className="fixed bottom-24 right-6 w-14 h-14 bg-primary text-white rounded-full shadow-fab flex items-center justify-center hover:scale-105 active:scale-95 transition-all z-40">
          <span className="material-symbols-outlined text-[32px]">add</span>
        </button>
      )}
    </div>
  );
};

export default App;

/**
 * AssetFlow Backend - Google Apps Script
 */

function doGet(e) {
  // Sử dụng evaluate() để cho phép nhúng mã script/css nếu cần
  return HtmlService.createTemplateFromFile('index')
    .evaluate()
    .setTitle('AssetFlow - Hệ thống Quản lý Tài sản IT')
    .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL)
    .addMetaTag('viewport', 'width=device-width, initial-scale=1');
}

function doPost(e) {
  var result = { "status": "error", "message": "Unknown action" };
  try {
    var data = JSON.parse(e.postData.contents);
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var timestamp = data.timestamp || new Date().toLocaleString('vi-VN');

    // 1. THÊM THIẾT BỊ
    if (data.action === 'ADD_DEVICE') {
      var sheet = ss.getSheets()[0];
      sheet.appendRow(["ID-" + Date.now(), data.tagId, data.name, data.type, data.location, data.configuration, "AVAILABLE", "", timestamp]);
      result = { "status": "success" };
    } 

    // 2. CHỈNH SỬA THIẾT BỊ
    else if (data.action === 'EDIT_DEVICE') {
      var devSheet = ss.getSheets()[0];
      var devData = devSheet.getDataRange().getValues();
      var tagIdToFind = data.tagId || data.tagid;

      for (var i = 1; i < devData.length; i++) {
        if (devData[i][1] == tagIdToFind) {
          devSheet.getRange(i + 1, 3).setValue(data.name);          
          devSheet.getRange(i + 1, 4).setValue(data.type);          
          devSheet.getRange(i + 1, 5).setValue(data.location);      
          devSheet.getRange(i + 1, 6).setValue(data.configuration); 
          devSheet.getRange(i + 1, 7).setValue(data.status);        
          devSheet.getRange(i + 1, 9).setValue(timestamp);          
          break;
        }
      }
      result = { "status": "success" };
    }

    // 3. CẤP PHÁT / THU HỒI
    else if (data.action === 'ASSIGN_DEVICE' || data.action === 'RETURN_DEVICE') {
      var devSheet = ss.getSheets()[0];
      var devData = devSheet.getDataRange().getValues();
      var tagIdToFind = data.tagId || data.tagid;

      for (var i = 1; i < devData.length; i++) {
        if (devData[i][1] == tagIdToFind) { 
          var newStatus = (data.action === 'ASSIGN_DEVICE') ? 'ASSIGNED' : 'AVAILABLE';
          var assignedTo = (data.action === 'ASSIGN_DEVICE') ? data.userName : "";
          devSheet.getRange(i + 1, 7).setValue(newStatus);
          devSheet.getRange(i + 1, 8).setValue(assignedTo);
          devSheet.getRange(i + 1, 9).setValue(timestamp);
          break;
        }
      }

      var histSheet = ss.getSheetByName("History") || ss.insertSheet("History");
      histSheet.appendRow([timestamp, tagIdToFind, data.action, data.performedBy || "Admin", data.userName || "Kho"]);
      result = { "status": "success" };
    }
  } catch (e) {
    result = { "status": "error", "message": e.toString() };
  }

  return ContentService.createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

